class Idempotency {
  static String v4() {
    final bytes = List<int>.generate(16, (i) => (DateTime.now().microsecondsSinceEpoch >> (i % 8) * 8) & 0xFF);
    bytes[6] = (bytes[6] & 0x0F) | 0x40;
    bytes[8] = (bytes[8] & 0x3F) | 0x80;
    String hex(int v) => v.toRadixString(16).padLeft(2, '0');
    final h = bytes.map(hex).join();
    return '${h.substring(0, 8)}-${h.substring(8, 12)}-${h.substring(12, 16)}-${h.substring(16, 20)}-${h.substring(20)}';
  }
}

class SensitiveLogger {
  final bool enabled;
  const SensitiveLogger({this.enabled = false});
  void log(String message, {Object? data}) {
    if (!enabled) return;
    if (kReleaseMode) return;
    debugPrint('[PAY] $message${data == null ? '' : ' | ${_redact(data)}'}');
  }

  String _redact(Object data) {
    final s = data is String ? data : jsonEncode(data);
    final patterns = <RegExp>[
      RegExp(r'("receipt"\s*:\s*")[^"]+(")', caseSensitive: false),
      RegExp(r'("token"\s*:\s*")[^"]+(")', caseSensitive: false),
      RegExp(r'("authorization"\s*:\s*")[^"]+(")', caseSensitive: false),
      RegExp(r'("client_secret"\s*:\s*")[^"]+(")', caseSensitive: false),
      RegExp(r'("paymentMethod"\s*:\s*")[^"]+(")', caseSensitive: false),
    ];
    var out = s;
    for (final p in patterns) {
      out = out.replaceAllMapped(p, (m) => '${m.group(1)}***${m.group(2)}');
    }
    return out;
  }
}

