class IapService {
  final InAppPurchase _iap = InAppPurchase.instance;
  final PaymentBackendClient backend;
  final SensitiveLogger logger;
  final bool allowAskToBuy;

  StreamSubscription<List<PurchaseDetails>>? _sub;
  final _purchaseController = StreamController<PaymentResult>.broadcast();

  Stream<PaymentResult> get purchaseResults => _purchaseController.stream;

  IapService({
    required this.backend,
    this.logger = const SensitiveLogger(enabled: false),
    this.allowAskToBuy = true,
  });

  Future<void> initialize() async {
    final available = await _iap.isAvailable();
    if (!available) throw PaymentException('iap_unavailable', 'In-app purchases not available');
    _sub?.cancel();
    _sub = _iap.purchaseStream.listen(_onPurchases, onError: (e, st) {
      _purchaseController.add(PaymentResult(
        provider: PaymentProviderType.inAppPurchase,
        status: PaymentStatus.failed,
        raw: {'error': e.toString()},
      ));
    });
    if (Platform.isIOS) {
      final addition = _iap.getPlatformAddition<InAppPurchaseStoreKitPlatformAddition>();
      await addition.setDelegate(_StoreKitDelegate(allowAskToBuy: allowAskToBuy));
    }
  }

  Future<List<ProductDetails>> queryProducts(Set<String> productIds) async {
    final resp = await _iap.queryProductDetails(productIds);
    if (resp.error != null) throw PaymentException('iap_query_error', resp.error!.message, details: resp.error);
    if (resp.productDetails.isEmpty) {
      throw PaymentException('iap_products_empty', 'No products returned for provided identifiers');
    }
    return resp.productDetails;
  }

  Future<void> buyConsumable({
    required ProductDetails product,
    required String customerId,
    required Map<String, dynamic> metadata,
  }) async {
    final param = PurchaseParam(productDetails: product);
    final ok = await _iap.buyConsumable(purchaseParam: param, autoConsume: Platform.isIOS);
    if (!ok) throw PaymentException('iap_buy_failed', 'Failed to start purchase flow');
    logger.log('IAP buy initiated', data: {'productId': product.id, 'customerId': customerId});
  }

  Future<void> buyNonConsumable({
    required ProductDetails product,
    required String customerId,
    required Map<String, dynamic> metadata,
  }) async {
    final param = PurchaseParam(productDetails: product);
    final ok = await _iap.buyNonConsumable(purchaseParam: param);
    if (!ok) throw PaymentException('iap_buy_failed', 'Failed to start purchase flow');
    logger.log('IAP buy initiated (non-consumable)', data: {'productId': product.id, 'customerId': customerId});
  }

  Future<void> restorePurchases() async {
    await _iap.restorePurchases();
  }

  Future<void> dispose() async {
    await _sub?.cancel();
    _sub = null;
    if (Platform.isIOS) {
      final addition = _iap.getPlatformAddition<InAppPurchaseStoreKitPlatformAddition>();
      await addition.setDelegate(null);
    }
    await _purchaseController.close();
  }

  Future<void> _onPurchases(List<PurchaseDetails> purchases) async {
    for (final p in purchases) {
      try {
        logger.log('IAP update', data: {
          'status': p.status.name,
          'productID': p.productID,
          'purchaseID': p.purchaseID,
          'pendingCompletePurchase': p.pendingCompletePurchase,
        });

        if (p.status == PurchaseStatus.pending) {
          _purchaseController.add(PaymentResult(
            provider: PaymentProviderType.inAppPurchase,
            status: PaymentStatus.pending,
            transactionId: p.purchaseID,
            productId: p.productID,
            raw: {'status': 'pending'},
          ));
          continue;
        }

        if (p.status == PurchaseStatus.canceled) {
          _purchaseController.add(PaymentResult(
            provider: PaymentProviderType.inAppPurchase,
            status: PaymentStatus.canceled,
            transactionId: p.purchaseID,
            productId: p.productID,
            raw: {'status': 'canceled'},
          ));
          continue;
        }

        if (p.status == PurchaseStatus.error) {
          _purchaseController.add(PaymentResult(
            provider: PaymentProviderType.inAppPurchase,
            status: PaymentStatus.failed,
            transactionId: p.purchaseID,
            productId: p.productID,
            raw: {'error': p.error?.message, 'details': p.error?.details},
          ));
          continue;
        }

        if (p.status == PurchaseStatus.purchased || p.status == PurchaseStatus.restored) {
          final idempotencyKey = Idempotency.v4();
          final platform = Platform.isIOS ? 'ios' : 'android';

          final receipt = _extractReceipt(p);
          if (receipt == null || receipt.isEmpty) {
            throw PaymentException('iap_missing_receipt', 'Missing purchase verification data');
          }

          final validation = await backend.validateIapReceipt(
            platform: platform,
            productId: p.productID,
            purchaseId: p.purchaseID ?? '',
            receipt: receipt,
            idempotencyKey: idempotencyKey,
            metadata: {
              'source': 'flutter',
              'status': p.status.name,
            },
          );

          final ok = (validation['ok'] == true) || (validation['status'] == 'succeeded');
          if (!ok) {
            throw PaymentException('iap_validation_failed', 'Receipt validation failed', details: validation);
          }

          _purchaseController.add(PaymentResult(
            provider: PaymentProviderType.inAppPurchase,
            status: PaymentStatus.succeeded,
            transactionId: p.purchaseID,
            productId: p.productID,
            receiptOrProof: null,
            raw: validation,
          ));
        }
      } catch (e) {
        _purchaseController.add(PaymentResult(
          provider: PaymentProviderType.inAppPurchase,
          status: PaymentStatus.failed,
          transactionId: p.purchaseID,
          productId: p.productID,
          raw: {'error': e.toString()},
        ));
      } finally {
        if (p.pendingCompletePurchase) {
          await _iap.completePurchase(p);
        }
      }
    }
  }

  String? _extractReceipt(PurchaseDetails p) {
    final vd = p.verificationData;
    if (vd.serverVerificationData.isNotEmpty) return vd.serverVerificationData;
    if (vd.localVerificationData.isNotEmpty) return vd.localVerificationData;
    return null;
  }
}

class _StoreKitDelegate implements SKPaymentQueueDelegateWrapper {
  final bool allowAskToBuy;
  _StoreKitDelegate({required this.allowAskToBuy});
  @override
  bool shouldContinueTransaction(SKPaymentTransactionWrapper transaction, SKStorefrontWrapper storefront) => true;

  @override
  bool shouldShowPriceConsent() => false;

  @override
  bool shouldAddStorePayment(SKPaymentWrapper payment, SKProductWrapper product) => allowAskToBuy;
