class WalletService {
  final PaymentBackendClient backend;
  final SensitiveLogger logger;
  final BiometricGuard biometricGuard;
  WalletService({
    required this.backend,
    this.logger = const SensitiveLogger(enabled: false),
    BiometricGuard? biometricGuard,
  }) : biometricGuard = biometricGuard ?? BiometricGuard();

  Future<PaymentResult> startWalletPayment({
    required String wallet,
    required int amountMinor,
    required String currency,
    required String customerId,
    required Map<String, dynamic> metadata,
    bool requireUserAuth = true,
  }) async {
    if (requireUserAuth) {
      await biometricGuard.requireAuth(reason: 'Confirm $wallet payment');
    }

    final idempotencyKey = Idempotency.v4();
    final session = await backend.createWalletSession(
      wallet: wallet,
      amountMinor: amountMinor,
      currency: currency,
      customerId: customerId,
      idempotencyKey: idempotencyKey,
      metadata: metadata,
    );

    final sessionId = (session['sessionId'] ?? session['id'] ?? '').toString();
    final redirectUrl = (session['redirectUrl'] ?? session['url'] ?? '').toString();
    if (redirectUrl.isEmpty || sessionId.isEmpty) {
      throw PaymentException('wallet_session_invalid', 'Wallet session did not include sessionId/redirectUrl', details: session);
    }

    logger.log('Wallet session created', data: {'wallet': wallet, 'sessionId': sessionId});

    final uri = Uri.parse(redirectUrl);
    final launched = await launchUrl(uri, mode: LaunchMode.externalApplication);
    if (!launched) {
      throw PaymentException('wallet_launch_failed', 'Failed to launch wallet URL');
    }

    return PaymentResult(
      provider: PaymentProviderType.wallet,
      status: PaymentStatus.pending,
      orderId: sessionId,
      raw: session,
    );
  }

  Future<PaymentResult> finalizeWalletPayment({
    required String sessionId,
    required Map<String, dynamic> proof,
  }) async {
    final idempotencyKey = Idempotency.v4();
    final res = await backend.finalizeWalletSession(
      sessionId: sessionId,
      idempotencyKey: idempotencyKey,
      proof: proof,
    );

    final status = (res['status'] ?? '').toString();
    final succeeded = status == 'succeeded' || res['ok'] == true;

    return PaymentResult(
      provider: PaymentProviderType.wallet,
      status: succeeded ? PaymentStatus.succeeded : PaymentStatus.failed,
      orderId: sessionId,
      transactionId: (res['transactionId'] ?? res['id'] ?? '').toString().isEmpty ? null : (res['transactionId'] ?? res['id']).toString(),
      raw: res,
    );
  }
}

class GatewayService {
  final PaymentBackendClient backend;
  final SensitiveLogger logger;
  final BiometricGuard biometricGuard;

  GatewayService({
    required this.backend,
    this.logger = const SensitiveLogger(enabled: false),
    BiometricGuard? biometricGuard,
  }) : biometricGuard = biometricGuard ?? BiometricGuard();

  Future<PaymentResult> payWithGateway({
    required int amountMinor,
    required String currency,
    required String customerId,
    required Map<String, dynamic> metadata,
    bool requireUserAuth = true,
  }) async {
    if (requireUserAuth) {
      await biometricGuard.requireAuth(reason: 'Confirm payment');
    }

    final idempotencyKey = Idempotency.v4();
    final intent = await backend.createGatewayPaymentIntent(
      amountMinor: amountMinor,
      currency: currency,
      customerId: customerId,
      idempotencyKey: idempotencyKey,
      metadata: metadata,
    );

    final intentId = (intent['intentId'] ?? intent['id'] ?? '').toString();
    if (intentId.isEmpty) throw PaymentException('gateway_intent_invalid', 'Gateway intent missing id', details: intent);

    logger.log('Gateway intent created', data: {'intentId': intentId});

    final proof = <String, dynamic>{
      'platform': Platform.operatingSystem,
      'client': 'flutter',
      'intentSnapshot': {
        'id': intentId,
        'createdAt': DateTime.now().toIso8601String(),
      },
    };

    final confirmed = await backend.confirmGatewayPayment(
      intentId: intentId,
      idempotencyKey: Idempotency.v4(),
      proof: proof,
    );

    final status = (confirmed['status'] ?? '').toString();
    final succeeded = status == 'succeeded' || confirmed['ok'] == true;

    return PaymentResult(
      provider: PaymentProviderType.gateway,
      status: succeeded ? PaymentStatus.succeeded : PaymentStatus.failed,
      orderId: (confirmed['orderId'] ?? intent['orderId'] ?? '').toString().isEmpty
          ? null
          : (confirmed['orderId'] ?? intent['orderId']).toString(),
      transactionId: (confirmed['transactionId'] ?? confirmed['id'] ?? intentId).toString(),
      raw: confirmed,
    );
  }
}

class PaymentModule {
  final PaymentConfig config;
  final PaymentBackendClient backend;
  final IapService iap;
  final WalletService wallet;
  final GatewayService gateway;
  final SensitiveLogger logger;

  PaymentModule._({
    required this.config,
    required this.backend,
    required this.iap,
    required this.wallet,
    required this.gateway,
    required this.logger,
  });

  factory PaymentModule({
    required PaymentConfig config,
    Future<String?> Function()? authTokenProvider,
    bool enableSensitiveLogs = false,
    http.Client? httpClient,
    Map<String, String> defaultHeaders = const {},
  }) {
    final logger = SensitiveLogger(enabled: enableSensitiveLogs);
    final backend = PaymentBackendClient(
      config,
      client: httpClient,
      authTokenProvider: authTokenProvider,
      defaultHeaders: defaultHeaders,
    );
    return PaymentModule._(
      config: config,
      backend: backend,
      iap: IapService(backend: backend, logger: logger, allowAskToBuy: config.allowStoreKitAskToBuy),
      wallet: WalletService(backend: backend, logger: logger),
      gateway: GatewayService(backend: backend, logger: logger),
      logger: logger,
    );
  }

  Future<void> initialize() async {
    await iap.initialize();
    if (Platform.isAndroid) {
      final addition = InAppPurchase.instance.getPlatformAddition<InAppPurchaseAndroidPlatformAddition>();
      await addition.enablePendingPurchases();
    }
  }

  Future<void> dispose() async {
    await iap.dispose();
    backend.close();
  }
}

class PciSafeCardInputTokenization {
  static const MethodChannel _channel = MethodChannel('payment_module/tokenization');

  static Future<Map<String, dynamic>> tokenizeCard({
    required String gateway,
    required Map<String, dynamic> billingDetails,
  }) async {
    final res = await _channel.invokeMethod<String>('tokenizeCard', {
      'gateway': gateway,
      'billingDetails': billingDetails,
    });
    if (res == null || res.isEmpty) throw PaymentException('tokenization_failed', 'Tokenization returned empty response');
    final decoded = jsonDecode(res);
    if (decoded is Map<String, dynamic>) return decoded;
    throw PaymentException('tokenization_bad_response', 'Tokenization response is not a JSON object');
  }
}